--[[ ACCESS DENIED ]]
local B=''
local T='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
local O={}
for i=1,#B,4 do
local a=(T:find(B:sub(i,i)) or 1)-1
local b=(T:find(B:sub(i+1,i+1)) or 1)-1
local c=(T:find(B:sub(i+2,i+2)) or 1)-1
local d=(T:find(B:sub(i+3,i+3)) or 1)-1
local n=a*262144+b*4096+c*64+d
O[#O+1]=string.char(math.floor(n/65536)%256)
if B:sub(i+2,i+2)~='=' then O[#O+1]=string.char(math.floor(n/256)%256) end
if B:sub(i+3,i+3)~='=' then O[#O+1]=string.char(n%256) end
end
loadstring(table.concat(O))()